/**
 * @summary Get all products (admin)
 */
export const getGetAdminProductsUrl = (params?: GetAdminProductsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/products?${stringifiedParams}`
    : `/api/admin/products`;
};

export const getAdminProducts = async (
  params?: GetAdminProductsParams,
  options?: RequestInit,
): Promise<AdminProductsResponse> => {
  return customFetch<AdminProductsResponse>(getGetAdminProductsUrl(params), {
    ...options,
    method: "GET",
  });
};

